proof fn phi_1_write_seq_read_unique_key(pt: PTMem, addr: usize, v1: usize, v2: usize)
    requires
        v1 != v2,
    ensures
        pt.write_seq(seq![(addr, v1)]).mem[addr] == v1,
{
    pt.lemma_write_seq_read(seq![(addr, v1)], 0);
}

proof fn phi_3_write_seq_read_does_not_require_domain(pt: PTMem, addr: usize, value: usize)
    requires
        !pt.mem.contains_key(addr),
    ensures
        pt.write_seq(seq![(addr, value)]).mem.contains_key(addr),
        pt.write_seq(seq![(addr, value)]).mem[addr] == value,
{
    pt.lemma_write_seq_read(seq![(addr, value)], 0);
}

proof fn phi_4_write_seq_drop_last_preserves_earlier(pt: PTMem, a1: usize, v1: usize, a2: usize, v2: usize)
